import { Link, useLocation } from 'react-router-dom';
import { tokens } from '../../shared/styles';

type AppShellProps = {
  children: React.ReactNode;
};

export const AppShell = ({ children }: AppShellProps) => {
  const location = useLocation();
  const isAuth = location.pathname === '/auth';

  return (
    <div style={{ minHeight: '100vh', background: '#f8fafc', color: '#0f172a', padding: 24, fontFamily: 'Inter, sans-serif' }}>
      <header style={{ marginBottom: 24, display: 'flex', justifyContent: 'space-between', alignItems: 'center', maxWidth: 1180, margin: '0 auto 24px' }}>
        <Link to="/" style={{ textDecoration: 'none', color: tokens.colors.text, fontSize: 24, fontWeight: 800 }}>CareDrop</Link>
        {!isAuth && (
          <nav style={{ display: 'flex', gap: 12 }}>
            <Link to="/" style={{ textDecoration: 'none', color: tokens.colors.textMuted }}>Home</Link>
            <Link to="/auth" style={{ textDecoration: 'none', color: tokens.colors.textMuted }}>Sign in</Link>
            <Link to="/dashboard" style={{ textDecoration: 'none', color: tokens.colors.textMuted }}>Dashboard</Link>
          </nav>
        )}
      </header>
      <main style={{ maxWidth: 1180, margin: '0 auto' }}>{children}</main>
    </div>
  );
};
